import { describe, it, expect, beforeAll, afterAll, jest } from '@jest/globals';
import mongoose from 'mongoose';

// Mock mongoose
jest.mock('mongoose', () => {
  const actualMongoose = jest.requireActual('mongoose');
  return {
    ...actualMongoose,
    connect: jest.fn().mockResolvedValue({}),
    disconnect: jest.fn().mockResolvedValue({}),
    Types: {
      ObjectId: {
        isValid: jest.fn().mockReturnValue(true),
      },
    },
  };
});

// Mock models
jest.mock('@/infrastructure/database/models/course.model', () => ({
  __esModule: true,
  default: {
    find: jest.fn(),
    findOne: jest.fn(),
    create: jest.fn(),
    updateOne: jest.fn(),
    updateMany: jest.fn(),
    deleteOne: jest.fn(),
    aggregate: jest.fn(),
    countDocuments: jest.fn(),
  },
}));

jest.mock('@/infrastructure/database/models/course_student.model', () => ({
  __esModule: true,
  default: {
    insertMany: jest.fn(),
    distinct: jest.fn(),
    aggregate: jest.fn(),
    find: jest.fn(),
  },
}));

describe('CourseService', () => {
  let CourseService: any;

  beforeAll(async () => {
    const module = await import('@/application/services/course.service');
    CourseService = module.CourseService;
  });

  describe('createCourse', () => {
    it('should create course with valid data', async () => {
      const CourseModel = require('@/infrastructure/database/models/course.model').default;
      CourseModel.create.mockResolvedValue({ _id: '123', name: 'Test Course' });

      const service = new CourseService();
      const result = await service.createCourse({ name: 'Test Course', start_date: '2026-05-01' });

      expect(CourseModel.create).toHaveBeenCalled();
      expect(result).toBeDefined();
    });

    it('should throw error if start_date is after end_date', async () => {
      const service = new CourseService();
      await expect(
        service.createCourse({
          name: 'Test',
          start_date: '2026-06-01',
          end_date: '2026-05-01',
        })
      ).rejects.toThrow();
    });
  });

  describe('assignStudentsToCourse', () => {
    it('should throw error if exceeds max_students', async () => {
      const CourseModel = require('@/infrastructure/database/models/course.model').default;
      const CourseStudentModel = require('@/infrastructure/database/models/course_student.model').default;

      CourseModel.findOne.mockResolvedValue({
        _id: 'course123',
        max_students: 5,
        name: 'Test',
      });
      CourseStudentModel.distinct.mockResolvedValue(['s1', 's2', 's3', 's4', 's5']); // 5 already enrolled

      const service = new CourseService();
      await expect(
        service.assignStudentsToCourse('course123', ['s6', 's7'])
      ).rejects.toThrow('vượt chỉ tiêu');
    });
  });
});
```

