import { CourseRepository } from '@/infrastructure/repositories/course.repository';
import { CourseModel } from '@/infrastructure/database/models/course.model';
import { ICourse } from '@/infrastructure/database/models/course.model';
import { StudentRepository } from '@/infrastructure/repositories/student.repository';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';
import { Response } from 'express';
import mongoose from 'mongoose';
import { LicenseCategoryModel } from '../../infrastructure/database/models/license_category.model';
import { CourseStudentModel } from '../../infrastructure/database/models/course_student.model';
import { PaginationOptions } from '@/domain/types/pagination.types';
import { COURSE_STATUS_DISPLAY, COURSE_TYPES } from '@/domain/constants/course.constants';
import { NotifyService } from './notify.service';
import fs from 'fs';
import { AppError } from '@/domain/exceptions/app-error';

export class CourseService {
  private courseRepository: CourseRepository;
  private studentRepository: StudentRepository;
  private excelHelper: ExcelHelper;
  private notifyService: NotifyService;

  constructor() {
    this.courseRepository = new CourseRepository();
    this.studentRepository = new StudentRepository();
    this.excelHelper = new ExcelHelper();
    this.notifyService = new NotifyService();
  }

  async getAllCourses(filters = {}, options: PaginationOptions = { page: 1, limit: 10 }, currentUser?: any) {
    return await this.courseRepository.findAll(filters, options, currentUser);
  }

  async getCourseById(id: string, currentUser?: any) {
    const course = await this.courseRepository.findById(id, currentUser);
    if (!course) {
      throw new Error('Không tìm thấy khóa học hoặc bạn không có quyền truy cập');
    }
    return course;
  }

  private async resolveLicenseCategoryId(data: Partial<ICourse>) {
    if (data.license_category_id && !mongoose.Types.ObjectId.isValid(String(data.license_category_id))) {
      const val = String(data.license_category_id);
      let cat = await LicenseCategoryModel.findOne({ code: val });
      if (!cat) {
        cat = await LicenseCategoryModel.findOne({ name: val });
      }

      if (cat) {
        data.license_category_id = cat._id as any;
      } else {
        delete data.license_category_id;
      }
    }
  }

  async createCourse(data: Partial<ICourse>) {
    if (data.code) {
      const existingCourse = await this.courseRepository.findByCode(data.code);
      if (existingCourse) {
        throw new AppError(`Mã khóa học "${data.code}" đã tồn tại trong hệ thống. Vui lòng sử dụng mã khác.`, 400);
      }
    }
    await this.resolveLicenseCategoryId(data);
    return await this.courseRepository.create(data);
  }

  async updateCourse(id: string, data: Partial<ICourse>, currentUser?: any) {
    if (data.code) {
      const existing = await this.courseRepository.findByCode(data.code);
      if (existing && existing._id.toString() !== id) {
        throw new AppError(`Mã khóa học "${data.code}" đã tồn tại trong hệ thống. Vui lòng sử dụng mã khác.`, 400);
      }
    }
    await this.resolveLicenseCategoryId(data);
    return await this.courseRepository.update(id, data);
  }

  async deleteCourse(id: string, currentUser?: any) {
    return await this.courseRepository.delete(id);
  }

  async assignStudentsToCourse(courseId: string, studentIds: string[]) {
    if (!studentIds || studentIds.length === 0) {
      throw new Error('Vui lòng chọn học viên');
    }
    const records = studentIds.map((sid) => ({
      student_id: sid,
      course_id: courseId,
      status: 'unfinished',
    }));
    return await CourseStudentModel.insertMany(records);
  }

  async getUnassignedStudents(filters = {}, options: PaginationOptions = { page: 1, limit: 100 }, currentUser?: any) {
    return await this.studentRepository.findUnassigned(filters, options, currentUser);
  }

  async exportCoursesToExcel(res: Response, filters: any, currentUser?: any): Promise<void> {
    const { data } = await this.courseRepository.findAll(filters, { page: 1, limit: 1000 }, currentUser);

    const { workbook, worksheet } = this.excelHelper.createWorkbook('Danh sách khóa học');

    this.excelHelper.applyHeaderStyle(worksheet, [
      { header: 'Mã khóa học', key: 'code', width: 15 },
      { header: 'Tên khóa học', key: 'name', width: 30 },
      { header: 'Hạng GPLX', key: 'license', width: 12 },
      { header: 'Hệ đào tạo', key: 'system', width: 20 },
      { header: 'Ngày khai giảng', key: 'start_date', width: 18 },
      { header: 'Ngày bế giảng', key: 'end_date', width: 18 },
      { header: 'Trạng thái', key: 'status', width: 15 },
    ]);

    data.forEach((c: any) => {
      worksheet.addRow({
        code: c.code || '',
        name: c.name || '',
        license: c.license_category_name || c.license_category_code || '',
        system: c.course_type || COURSE_TYPES.DIRECT,
        start_date: c.start_date ? new Date(c.start_date).toLocaleDateString('vi-VN') : '',
        end_date: c.end_date ? new Date(c.end_date).toLocaleDateString('vi-VN') : '',
        status: COURSE_STATUS_DISPLAY[c.status as keyof typeof COURSE_STATUS_DISPLAY] || c.status,
      });
    });

    this.excelHelper.applyRowStyle(worksheet);
    await this.excelHelper.sendWorkbook(res, workbook, 'danh_sach_khoa_hoc');
  }

  async getCourseImportTemplate(res: Response) {
    return await this.excelHelper.getCourseImportTemplate(res);
  }

  async getCourseStats(currentUser?: any) {
    return await this.courseRepository.getStats(currentUser);
  }

  async importCoursesFromExcel(filePath: string, userId: string, userRole: string = 'user') {
    const runImport = async () => {
      try {
        const data = await this.excelHelper.parseCourseExcel(filePath);
        const results = {
          success: 0,
          failed: 0,
          errors: [] as any[],
        };

        const licenseCats = await LicenseCategoryModel.find({ is_deleted: { $ne: true } })
          .lean()
          .exec();

        for (const item of data) {
          try {
            if (!item.name || !item.code) {
              results.failed++;
              results.errors.push({ name: item.name || 'Ẩn danh', error: 'Thiếu tên hoặc mã khóa học' });
              continue;
            }

            // Resolve license category ID
            const category = licenseCats.find(
              (lc) =>
                lc.name.toLowerCase().includes(item.licenseRank.toLowerCase()) ||
                lc.code.toLowerCase() === item.licenseRank.toLowerCase(),
            );

            if (!category && item.licenseRank) {
              results.failed++;
              results.errors.push({ name: item.name, error: `Không tìm thấy hạng đào tạo: ${item.licenseRank}` });
              continue;
            }

            // Map course type
            const courseType = item.courseType?.toLowerCase().includes('nâng') ? 'Nâng hạng' : 'Học trực tiếp';

            await this.courseRepository.create({
              name: item.name,
              code: item.code,
              license_category_id: category?._id,
              course_type: courseType,
              start_date: item.startDate,
              end_date: item.endDate,
              max_students: item.maxStudents,
              course_fee: item.courseFee,
              note: item.note,
              status: 'draft',
              teacher_id: userId as any,
            });

            results.success++;

            // Progress notification
            if (results.success % 5 === 0) {
              await this.notifyService.send({
                userId,
                title: '⏳ Đang nhập khóa học...',
                content: `Đã xử lý thành công ${results.success} khóa học.`,
                channel: 'in_app',
              });
            }
          } catch (error: any) {
            results.failed++;
            results.errors.push({ name: item.name, error: error.message });
          }
        }

        // Final notification
        await this.notifyService.send({
          userId,
          title: '📑 Hoàn tất nhập danh sách khóa học',
          content: `Đã xử lý xong file Excel.\n✅ Thành công: ${results.success}\n❌ Lỗi: ${results.failed}${
            results.errors.length > 0
              ? `\nChi tiết lỗi: ${results.errors
                  .slice(0, 3)
                  .map((e) => `${e.name}: ${e.error}`)
                  .join('; ')}${results.errors.length > 3 ? '...' : ''}`
              : ''
          }`,
          channel: 'in_app',
        });
      } catch (error: any) {
        console.error('Course import failed:', error);
        await this.notifyService.send({
          userId,
          title: 'Lỗi nhập danh sách khóa học',
          content: `Đã xảy ra lỗi nghiêm trọng: ${error.message}`,
          channel: 'in_app',
        });
      } finally {
        if (fs.existsSync(filePath)) {
          fs.unlinkSync(filePath);
        }
      }
    };

    runImport();
    return { message: 'Quá trình nhập dữ liệu đã bắt đầu chạy ngầm' };
  }

  async getTodayMilestones(teacherId: string) {
    const teacherOid = new mongoose.Types.ObjectId(teacherId);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    // Courses starting today (Sắp KG -> Đang học)
    const openingCourses = await CourseStudentModel.aggregate([
      { $match: { teacher_id: teacherOid } },
      {
        $lookup: {
          from: 'courseinfos',
          localField: 'course_id',
          foreignField: '_id',
          as: 'course',
        },
      },
      { $unwind: { path: '$course', preserveNullAndEmptyArrays: false } },
      {
        $match: {
          'course.start_date': { $gte: today, $lt: tomorrow },
          'course.status': 'draft',
        },
      },
      {
        $project: {
          _id: '$course._id',
          name: '$course.name',
          start_date: '$course.start_date',
          end_date: '$course.end_date',
          status: '$course.status',
          student_count: 1,
        },
      },
    ]);

    // Courses ending today (Đang học -> Đã kết thúc)
    const closingCourses = await CourseStudentModel.aggregate([
      { $match: { teacher_id: teacherOid } },
      {
        $lookup: {
          from: 'courseinfos',
          localField: 'course_id',
          foreignField: '_id',
          as: 'course',
        },
      },
      { $unwind: { path: '$course', preserveNullAndEmptyArrays: false } },
      {
        $match: {
          'course.end_date': { $gte: today, $lt: tomorrow },
          'course.status': 'ongoing',
        },
      },
      {
        $project: {
          _id: '$course._id',
          name: '$course.name',
          start_date: '$course.start_date',
          end_date: '$course.end_date',
          status: '$course.status',
          student_count: 1,
        },
      },
    ]);

    return {
      openingCourses,
      closingCourses,
      openingCount: openingCourses.length,
      closingCount: closingCourses.length,
    };
  }

  async bulkUpdateCourseStatus(courseIds: string[], newStatus: string, teacherId: string) {
    const teacherOid = new mongoose.Types.ObjectId(teacherId);
    const validStatuses = ['draft', 'ongoing', 'completed', 'canceled'];
    if (!validStatuses.includes(newStatus)) {
      throw new AppError('Trạng thái không hợp lệ', 400);
    }

    // Verify teacher owns these courses before updating
    const courseOids = courseIds.map((id) => new mongoose.Types.ObjectId(id));
    const enrolledCourses = await CourseStudentModel.distinct('course_id', {
      teacher_id: teacherOid,
      course_id: { $in: courseOids },
    });

    const validCourseIds = enrolledCourses.map((id) => id.toString());
    const unauthorized = courseIds.filter((id) => !validCourseIds.includes(id));
    if (unauthorized.length > 0) {
      throw new AppError('Bạn không có quyền cập nhật một số khóa học', 403);
    }

    const result = await CourseModel.updateMany(
      { _id: { $in: courseOids } },
      { $set: { status: newStatus, updated_at: new Date() } }
    );

    return { updated: result.modifiedCount, courseIds: validCourseIds };
  }
}

import mongoose from 'mongoose';
import { StudentRepository } from '@/infrastructure/repositories/student.repository';
import { SettingsRepository } from '@/infrastructure/database/repositories/settings.repository';
import { PaymentRepository } from '@/infrastructure/repositories/payment.repository';
import { IStudent } from '@/domain/interfaces/student.interface';
import { COURSE_TYPES } from '@/domain/constants/course.constants';
import { STUDENT_STATUSES } from '@/domain/constants/student.constants';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';
import { Response } from 'express';
import { SystemLogModel } from '../../infrastructure/database/models/system_log.model';
import { StudentModel } from '../../infrastructure/database/models/student.model';
import { CourseStudentModel } from '../../infrastructure/database/models/course_student.model';
import { CourseModel } from '../../infrastructure/database/models/course.model';
import { LicenseCategoryModel } from '../../infrastructure/database/models/license_category.model';
import { CityModel } from '../../infrastructure/database/models/city.model';
import { NotificationModel } from '../../infrastructure/database/models/notification.model';
import { UserService } from './user.service';
import { NotifyService } from './notify.service';
import { StatusTransitionHelper } from './status-transition.helper';
import { PaginationOptions } from '@/domain/types/pagination.types';
import fs from 'fs';
import logger from '@/infrastructure/logging/logger';
import { AppError } from '@/domain/exceptions/app-error';
import { UserModel } from '../../infrastructure/database/models/user.model';
import { RoleModel, UserRoleName } from '../../infrastructure/database/models/role.model';
import { UserRoleModel } from '../../infrastructure/database/models/user_role.model';

export class StudentService {
  private studentRepository: StudentRepository;
  private paymentRepository: PaymentRepository;
  private userService: UserService;
  private excelHelper: ExcelHelper;
  private notifyService: NotifyService;
  private settingsRepository: SettingsRepository;

  constructor() {
    this.studentRepository = new StudentRepository();
    this.paymentRepository = new PaymentRepository();
    this.userService = new UserService();
    this.excelHelper = new ExcelHelper();
    this.notifyService = new NotifyService();
    this.settingsRepository = new SettingsRepository();
  }

  async getAllStudents(filters = {}, options: PaginationOptions = { page: 1, limit: 10 }, currentUser?: any) {
    return await this.studentRepository.findAll(filters, options, currentUser);
  }

  async getStudentById(id: string, currentUser?: any) {
    const student = await this.studentRepository.findById(id, currentUser);
    if (!student) {
      throw new AppError('Học viên không tồn tại hoặc bạn không có quyền truy cập', 404);
    }
    return student;
  }

  async updateStudent(id: string, data: any) {
    const student = await this.studentRepository.findById(id);
    if (!student) throw new AppError('Học viên không tồn tại', 404);

    // Business Logic Guard: Validate status transition if requested
    if (data.status) {
      StatusTransitionHelper.validate(student, data.status);
    }

    // 1. Update Core User Data
    const userId = (student.user_id as any)._id || student.user_id;
    const coreFields = [
      'name',
      'first_name',
      'last_name',
      'phone',
      'identity_number',
      'identity_card',
      'email',
      'existing_license_num',
      'existing_license_rank',
    ];
    if (Object.keys(data).some((k) => coreFields.includes(k))) {
      await this.userService.updateUserProfile(userId, data);
    }

    // 2. Map and Update Core Student Attributes (Demographics & Category)
    const demographicUpdate: any = {};
    if (data.city !== undefined) {
      demographicUpdate.region_id =
        data.city === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.city)
            ? new mongoose.Types.ObjectId(data.city)
            : data.city;
    }
    if (data.region_id !== undefined) {
      demographicUpdate.region_id =
        data.region_id === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.region_id)
            ? new mongoose.Types.ObjectId(data.region_id)
            : data.region_id;
    }

    // ENSURE: license_category_id is ALSO updated on the Student document, not just CourseStudent
    if (data.rank !== undefined && data.rank !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.rank);
    } else if (data.license_category_id !== undefined && data.license_category_id !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.license_category_id);
    }

    if (data.status !== undefined && data.status !== '') {
      let sanitizedStatus = data.status;
      if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';
      demographicUpdate.status_detail = sanitizedStatus;
    }

    if (data.lead_manager !== undefined) {
      demographicUpdate.lead_manager = data.lead_manager === '' ? null : data.lead_manager;
    }

    if (Object.keys(demographicUpdate).length > 0) {
      await this.studentRepository.update(id, demographicUpdate);
    }

    // 3. Map Course details for latest CourseStudent Enrollment
    const courseUpdate = await this._mapCourseUpdateData(data);

    const needsEnrollmentUpdate =
      Object.keys(courseUpdate).length > 0 ||
      [
        'health_check_status',
        'health_check_date',
        'hospital_id',
        'health_check_note',
        'theory_completed',
        'sand_yard_completed',
        'simulation_completed',
        'dat_completed',
        'cabin_completed',
        'graduation_eligible',
      ].some((k) => data[k] !== undefined);

    if (needsEnrollmentUpdate) {
      const latestEnrollment = await CourseStudentModel.findOne({ student_id: id }).sort({ created_at: -1 });
      if (latestEnrollment) {
        this._mergeLatestEnrollmentFlags(courseUpdate, latestEnrollment, data);
        await CourseStudentModel.updateOne({ _id: latestEnrollment._id }, { $set: courseUpdate });
      } else {
        const fallbackCourseId =
          courseUpdate.course_id ||
          (student as any).course_id ||
          data.course_id ||
          data.course ||
          null;

        const fallbackLicenseCategoryId =
          courseUpdate.license_category_id ||
          (student as any).license_category_id ||
          null;

        if (fallbackCourseId) {
          const newEnrollment: any = {
            student_id: id,
            course_id: fallbackCourseId,
          };

          if (fallbackLicenseCategoryId) {
            newEnrollment.license_category_id = fallbackLicenseCategoryId;
          }

          this._mergeLatestEnrollmentFlags(newEnrollment, { health_check: {}, progress_flags: {} }, data);

          if (!newEnrollment.status_detail) {
            newEnrollment.status_detail = (student as any).status_detail || 'Chờ KSK';
          }

          if (courseUpdate.fee !== undefined) {
            newEnrollment.fee = courseUpdate.fee;
          }

          await CourseStudentModel.create(newEnrollment);
        } else {
          logger.warn('updateStudent: skipped enrollment-linked update because no enrollment/course could be resolved', {
            studentId: id,
            keys: Object.keys(data || {}),
          });
          throw new AppError(
            'Không thể cập nhật hồ sơ khám sức khỏe vì học viên chưa có khóa học/enrollment để lưu dữ liệu.',
            400,
          );
        }
      }
    }

    return await this.studentRepository.findById(id);
  }

  private async _mapCourseUpdateData(data: any): Promise<any> {
    const courseUpdate: any = {};
    if (data.status !== undefined) {
      // Sanitize old status labels coming from legacy clients or old constants
      let sanitizedStatus = data.status;
      if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';
      courseUpdate.status_detail = sanitizedStatus;
    }
    if (data.course !== undefined && data.course !== '') {
      courseUpdate.course_id = data.course;
      // Fetch course fee to initialize tuition
      const course = await CourseModel.findById(data.course).select('course_fee').lean().exec();
      if (course) {
        courseUpdate.fee = (course as any).course_fee || 0;
      }
    }

    // Support both 'rank' string and 'license_category_id' ObjectId
    const rankValue = data.rank || data.license_category_id;
    if (rankValue !== undefined && rankValue !== '') {
      courseUpdate.license_category_id = await this._resolveLicenseCategoryId(rankValue);
    }
    return courseUpdate;
  }

  private async _resolveLicenseCategoryId(rank: string | null | undefined): Promise<any> {
    if (!rank) return null;
    // Already an ObjectId
    if (mongoose.Types.ObjectId.isValid(rank)) return rank;

    const normalized = rank.trim().toUpperCase();

    // 1. Exact match by code or name
    const exact = await LicenseCategoryModel.findOne({
      $or: [
        { code: { $regex: `^${normalized}$`, $options: 'i' } },
        { name: { $regex: `^${normalized}$`, $options: 'i' } },
        { name: { $regex: `^H\u1ea1ng ${normalized}$`, $options: 'i' } },
      ],
    }).exec();
    if (exact) return exact._id;

    // 2. Prefix fallback: 'B2' → tries 'B', 'A1' → tries 'A', etc.
    const prefix = normalized.replace(/\d+$/, '');
    if (prefix && prefix !== normalized) {
      const fallback = await LicenseCategoryModel.findOne({
        $or: [
          { code: { $regex: `^${prefix}$`, $options: 'i' } },
          { name: { $regex: `^${prefix}$`, $options: 'i' } },
          { name: { $regex: `^H\u1ea1ng ${prefix}$`, $options: 'i' } },
        ],
      }).exec();
      if (fallback) {
        logger.info('_resolveLicenseCategoryId: prefix fallback matched', { input: rank, matched: fallback.code });
        return fallback._id;
      }
    }

    logger.warn('_resolveLicenseCategoryId: no match found', { rank });
    return null;
  }

  private _mergeLatestEnrollmentFlags(courseUpdate: any, latestEnrollment: any, data: any) {
    const { health_check_status, health_check_date, hospital_id, health_check_note } = data;
    if ([health_check_status, health_check_date, hospital_id, health_check_note].some((v) => v !== undefined)) {
      const hc: any = latestEnrollment.health_check || {};

      let parsedDate = hc.date ?? null;
      if (health_check_date === '' || health_check_date === null) {
        parsedDate = null;
      } else if (health_check_date && health_check_date !== 'Invalid Date') {
        const d = new Date(health_check_date);
        if (!isNaN(d.getTime())) {
          parsedDate = d;
        }
      }

      courseUpdate.health_check = {
        status: health_check_status ?? hc.status ?? 'Chờ khám',
        date: parsedDate,
        hospital: hospital_id ?? hc.hospital ?? null,
        note: health_check_note ?? hc.note ?? null,
      };

      // --- DATA SYNCHRONIZATION: Health Check -> Dashboard Status ---
      // If health check status is updated to 'Đủ điều kiện', auto-set dashboard status to 'Đã KSK'
      // This ensures dashboard stats stay in sync with actual biological/medical progress.
      if (courseUpdate.health_check.status === 'Đủ điều kiện' && courseUpdate.status_detail !== 'Đã KSK') {
        courseUpdate.status_detail = 'Đã KSK';
      } else if (courseUpdate.health_check.status === 'Chờ khám' && latestEnrollment.status_detail === 'Đã KSK') {
        // If downgraded or reset, sync back to 'Chờ KSK'
        courseUpdate.status_detail = 'Chờ KSK';
      }
    }

    const {
      theory_completed,
      sand_yard_completed,
      simulation_completed,
      dat_completed,
      cabin_completed,
      graduation_eligible,
    } = data;
    if (
      [
        theory_completed,
        sand_yard_completed,
        simulation_completed,
        dat_completed,
        cabin_completed,
        graduation_eligible,
      ].some((v) => v !== undefined)
    ) {
      const pf: any = latestEnrollment.progress_flags || {};
      courseUpdate.progress_flags = {
        theory_completed: theory_completed ?? pf.theory_completed ?? false,
        sand_yard_completed: sand_yard_completed ?? pf.sand_yard_completed ?? false,
        simulation_completed: simulation_completed ?? pf.simulation_completed ?? false,
        dat_completed: dat_completed ?? pf.dat_completed ?? false,
        cabin_completed: cabin_completed ?? pf.cabin_completed ?? false,
        graduation_eligible: graduation_eligible ?? pf.graduation_eligible ?? false,
      };

      // --- DATA SYNCHRONIZATION: Exam Eligibility ---
      // If graduation_eligible is true, and status is still a training status, advance it to 'Đang thi'
      if (
        courseUpdate.progress_flags.graduation_eligible &&
        ['Đang học', 'Đang học LT', 'Đang học TH', 'Đã KSK', 'Nộp HS'].includes(latestEnrollment.status_detail)
      ) {
        courseUpdate.status_detail = 'Đang thi';
      }
    }
  }

  private async validateRequiredFields(data: any, userId: string) {
    const settings = await this.settingsRepository.findByUserId(userId);
    if (!settings || !settings.requiredFields || settings.requiredFields.length === 0) return;

    const MAPPING: Record<string, { field: string; label: string }> = {
      name: { field: 'name', label: 'Họ và tên' }, // Custom handling for name
      phone: { field: 'phone', label: 'Số điện thoại' },
      intro: { field: 'lead_manager', label: 'Người giới thiệu' },
      dob: { field: 'dob', label: 'Ngày sinh' },
      cccd: { field: 'identity_card', label: 'CCCD / CMND' },
      address: { field: 'address', label: 'Địa chỉ chi tiết' },
      rank: { field: 'license_category_id', label: 'Hạng bằng' },
      region: { field: 'region_id', label: 'Tỉnh / Thành phố' },
      course: { field: 'course_id', label: 'Khóa học' },
      regDate: { field: 'contract_date', label: 'Ngày đăng ký' },
    };

    for (const fieldId of settings.requiredFields) {
      const mapping = MAPPING[fieldId];
      if (!mapping) continue;

      if (fieldId === 'name') {
        if (!data.first_name || !data.last_name) {
          throw new AppError(`Trường [${mapping.label}] là bắt buộc`, 400);
        }
      } else {
        const value = data[mapping.field];
        if (value === undefined || value === null || value === '') {
          throw new AppError(`Trường [${mapping.label}] là bắt buộc`, 400);
        }
      }
    }
  }

  async createStudent(data: any, currentUser?: any) {
    const {
      phone,
      identity_card,
      user_id,
      region_id,
      course_id,
      fee,
      status_detail,
      license_category_id,
      amount,
      installment,
      lead_manager,
      student_code,
      teacher_id,
      contract_date,
      existing_license_num,
      existing_license_rank,
    } = data;

    // Dynamic settings validation
    if (currentUser?.id) {
      await this.validateRequiredFields(data, currentUser.id);
    }

    logger.info(`[StudentService.createStudent] Payload check:`, {
      teacher_id,
      phone,
      identity_card,
      existing_license_num,
      existing_license_rank
    });

    let targetUserId = user_id;

    // Sanitize status_detail
    let sanitizedStatus = status_detail || (course_id ? 'Đã vào khóa' : 'Chờ KSK');
    if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';

    if (!targetUserId) {
      const existingUser = await this.userService.findExistingUser(phone, identity_card);
      if (existingUser) {
        // Check if this user already has a student record
        const existingStudent = await StudentModel.findOne({ user_id: existingUser._id, is_deleted: false }).exec();
        if (existingStudent) {
          throw new AppError('Học viên với số điện thoại hoặc CCCD này đã tồn tại.', 400);
        }

        // Update the existing user with any new license info provided
        if (existing_license_num || existing_license_rank) {
          await this.userService.updateUserProfile(existingUser._id.toString(), {
            existing_license_num,
            existing_license_rank
          });
        }

        targetUserId = existingUser._id;
      } else {
        const user = await this.userService.createStudentUser(data);
        targetUserId = user._id;
      }
    } else {
      // Check if this specific user_id is already a student
      const existingStudent = await StudentModel.findOne({ user_id: targetUserId, is_deleted: false }).exec();
      if (existingStudent) {
        throw new AppError('Người dùng này đã có hồ sơ học viên trên hệ thống.', 400);
      }
    }

    // Capture rank and status for the student profile (StudentInfos)
    const licenseCategoryId = await this._resolveLicenseCategoryId(license_category_id);

    let resolvedRegionId;
    if (region_id && typeof region_id === 'string' && !mongoose.Types.ObjectId.isValid(region_id)) {
      const city = await CityModel.findOne({ name: region_id }).select('_id').lean().exec();
      resolvedRegionId = city ? (city as any)._id : null;
    } else if (region_id && mongoose.Types.ObjectId.isValid(region_id)) {
      resolvedRegionId = new mongoose.Types.ObjectId(region_id);
    } else {
      resolvedRegionId = null;
    }

    const student = await this.studentRepository.create({
      user_id: targetUserId,
      region_id: resolvedRegionId as any,
      license_category_id: licenseCategoryId,
      status_detail: sanitizedStatus,
      lead_manager: lead_manager || null,
      student_code: student_code || null,
      teacher_id: teacher_id ? new mongoose.Types.ObjectId(teacher_id) : null,
    });

    if (course_id) {
      let actualFee = fee;
      if (!actualFee || actualFee === 0) {
        const course = await CourseModel.findById(course_id).select('course_fee').lean().exec();
        actualFee = (course as any)?.course_fee || 0;
      }

      const enrollment = await CourseStudentModel.create({
        student_id: student._id,
        course_id: course_id,
        teacher_id: teacher_id ? new mongoose.Types.ObjectId(teacher_id) : null,
        license_category_id: licenseCategoryId,
        fee: actualFee,
        status_detail: sanitizedStatus,
        contract_date: contract_date || null,
      });

      // Create initial payment if amount > 0
      if (amount && amount > 0) {
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        const { PaymentModel } = require('@/infrastructure/database/models/payment.model');
        const receiptCode = await this.paymentRepository.getNextReceiptCode();

        await PaymentModel.create({
          course_student_id: enrollment._id,
          payment_date: new Date(),
          received_fee: amount,
          type: 'tuition_fee',
          stage_name: installment || 'Lần đóng 1',
          note: receiptCode,
          is_received: true,
        });
      }
    }

    // Return enriched data for immediate UI feedback
    return await this.getStudentById(student._id.toString());
  }

  async deleteStudent(id: string, currentUser?: any) {
    // 1. Verify existence and ownership
    await this.getStudentById(id, currentUser);

    // 2. Cascade delete any course enrollments mapped to this student
    await CourseStudentModel.deleteMany({ student_id: id });
    return await this.studentRepository.delete(id);
  }

  async bulkDeleteStudents(ids: string[], currentUser?: any) {
    if (!ids || ids.length === 0) {
      throw new Error('Danh sách ID không được để trống');
    }

    // 1. Verify existence and ownership for all
    // We could optimize this, but for safety we check all
    for (const id of ids) {
      await this.getStudentById(id, currentUser);
    }

    // 2. Cascade delete enrollments for all
    await CourseStudentModel.deleteMany({ student_id: { $in: ids } });

    // 3. Batch delete students
    return await this.studentRepository.deleteMany(ids);
  }

  async exportStudentsToExcel(res: Response, filters: any, currentUser?: any): Promise<void> {
    const { data } = await this.studentRepository.findAll(filters, { page: 1, limit: 5000 }, currentUser);

    const { workbook, worksheet } = this.excelHelper.createWorkbook('Danh sách học viên');

    this.excelHelper.applyHeaderStyle(worksheet, [
      { header: 'Họ và tên', key: 'name', width: 25 },
      { header: 'Số điện thoại', key: 'phone', width: 15 },
      { header: 'CCCD/CMND', key: 'id_card', width: 15 },
      { header: 'Hạng GPLX', key: 'license', width: 12 },
      { header: 'Hệ đào tạo', key: 'system', width: 15 },
      { header: 'Khu vực', key: 'region', width: 15 },
      { header: 'Trạng thái', key: 'status', width: 20 },
      { header: 'Ngày đăng ký', key: 'created_at', width: 15 },
    ]);

    data.forEach((s: any) => {
      const user = s.user_id || {};
      worksheet.addRow({
        name: `${user.last_name || ''} ${user.first_name || ''}`.trim(),
        phone: user.phone || '',
        id_card: user.id_card || '',
        license: s.license_category_name || '',
        system: s.course_type || '',
        region: s.region_name || s.region_id?.name || '',
        status: s.status_detail || s.status_main || '',
        created_at: s.created_at ? new Date(s.created_at).toLocaleDateString('vi-VN') : '',
      });
    });

    this.excelHelper.applyRowStyle(worksheet);
    await this.excelHelper.sendWorkbook(res, workbook, 'danh_sach_hoc_vien');
  }

  async getStudentHistory(id: string, options: PaginationOptions = { page: 1, limit: 20 }) {
    const { page, limit } = options;
    const skip = (page - 1) * limit;

    const logs = await SystemLogModel.find({ entity_id: id })
      .sort({ created_at: -1 })
      .skip(skip)
      .limit(limit)
      .populate('user_id', 'first_name last_name email')
      .exec();

    const total = await SystemLogModel.countDocuments({ entity_id: id });

    return {
      data: logs,
      meta: {
        total,
        page,
        limit,
        total_pages: Math.ceil(total / limit),
      },
    };
  }

  async isStudentAssignedToTeacher(studentId: string, teacherId: string): Promise<boolean> {
    // 1. Check in Enrollments
    const enrolled = await CourseStudentModel.countDocuments({
      student_id: studentId,
      teacher_id: teacherId,
    });
    if (enrolled > 0) return true;

    // 2. Check in Direct Ownership
    const owned = await StudentModel.countDocuments({
      _id: studentId,
      teacher_id: teacherId,
    });
    return owned > 0;
  }

  async getImportManagementStats(currentUser?: any) {
    const baseMatch: any = { is_deleted: false };

    if (currentUser?.role === 'teacher') {
      const assignedIds = await this.studentRepository.getAssignedStudentIds(currentUser.id);
      baseMatch._id = { $in: assignedIds };
    }

    const [total, enrolled, unassigned, waiting, remaining, today] = await Promise.all([
      StudentModel.countDocuments(baseMatch),
      StudentModel.countDocuments({ ...baseMatch, status_detail: 'Đã vào khóa' }),
      StudentModel.countDocuments({ ...baseMatch, status_detail: 'Chưa vào khóa' }),
      StudentModel.countDocuments({ ...baseMatch, status_detail: 'Chờ xếp khóa' }),
      StudentModel.countDocuments({ ...baseMatch, status_detail: 'Học viên tồn' }),
      StudentModel.countDocuments({
        ...baseMatch,
        created_at: { $gte: new Date().setHours(0, 0, 0, 0) },
      }),
    ]);

    return { total, today, enrolled, unassigned, waiting, remaining };
  }

  /**
   * Get list of potential leads (Managers/Sales/Staff)
   */
  async getLeads() {
    // 1. Find roles that can be managers
    const targetRoles = [UserRoleName.Lead, UserRoleName.Sale, UserRoleName.Staff, UserRoleName.Admin];
    const roles = await RoleModel.find({ role_name: { $in: targetRoles } })
      .select('_id role_name')
      .lean()
      .exec();
    const roleIds = roles.map((r) => r._id);

    // 2. Find user links with those roles
    const userRoleLinks = await UserRoleModel.find({ role_id: { $in: roleIds } })
      .select('user_id')
      .lean()
      .exec();
    const userIds = userRoleLinks.map((link) => link.user_id);

    // 3. Get user details
    const users = await UserModel.find({
      _id: { $in: userIds },
      status: 'active',
    })
      .select('_id first_name last_name email phone')
      .sort({ last_name: 1, first_name: 1 })
      .lean()
      .exec();

    return users.map((u) => ({
      _id: u._id,
      name: `${u.last_name} ${u.first_name}`.trim(),
      email: u.email,
      phone: u.phone,
    }));
  }

  /**
   * Resolve course by code or create a new one.
   * Always creates when code is not yet in DB.
   */
  private async _findOrCreateCourse(data: any, teacherId?: string): Promise<any> {
    if (!data.courseCode) return null;

    logger.info('_findOrCreateCourse called', {
      courseCode: data.courseCode,
      courseName: data.courseName,
      trainingGrade: data.trainingGrade,
      courseStartDate: data.courseStartDate,
    });

    // 1. Try to find existing course by code
    const existing = await CourseModel.findOne({ code: data.courseCode }).select('_id').lean().exec();
    if (existing) {
      logger.info('Course already exists', { courseCode: data.courseCode, courseId: (existing as any)._id });
      return (existing as any)._id;
    }

    // 2. Not found — always create (use courseCode as fallback name)
    const licenseCategoryId = await this._resolveLicenseCategoryId(data.trainingGrade);

    const course = await CourseModel.create({
      code: data.courseCode,
      name: data.courseName || data.courseCode,
      start_date: data.courseStartDate || null,
      end_date: data.courseEndDate || null,
      license_category_id: licenseCategoryId || null,
      teacher_id: teacherId ? new mongoose.Types.ObjectId(teacherId) : null,
      status: 'ongoing',
      course_type: 'trực tiếp',
    });

    logger.info('Auto-created course during import', { courseCode: data.courseCode, courseId: course._id });
    return course._id;
  }

  async importStudentsFromExcel(
    filePath: string,
    userId: string,
    userRole: string = 'user',
    courseId?: string,
    importType: 'student_only' | 'student_and_course' = 'student_only',
  ) {
    // We do NOT await this in the controller. It runs in the background.
    const runImport = async () => {
      try {
        const data = await this.excelHelper.parseStudentExcel(filePath);
        const results = {
          success: 0,
          failed: 0,
          skipped: 0,
          errors: [] as any[],
        };

        for (const item of data) {
          try {
            if (!item.firstName) {
              results.failed++;
              results.errors.push({ name: 'Ẩn danh', error: 'Thiếu tên học viên' });
              continue;
            }

            // For student_and_course import, some fields are mandatory
            if (importType === 'student_and_course') {
              if (!item.dob) {
                results.failed++;
                results.errors.push({ name: item.firstName, error: 'Thiếu ngày sinh (bắt buộc cho import học viên và khóa)' });
                continue;
              }
              if (!item.identity_card) {
                results.failed++;
                results.errors.push({ name: item.firstName, error: 'Thiếu CCCD/CMND (bắt buộc cho import học viên và khóa)' });
                continue;
              }
              if (!item.courseCode) {
                results.failed++;
                results.errors.push({ name: item.firstName, error: 'Thiếu mã khóa học (bắt buộc cho import học viên và khóa)' });
                continue;
              }
            }

            const duplicate = await this.userService.findExistingUser(item.phone, item.identity_card);
            if (duplicate) {
              // Only skip if the user is ALREADY a student
              const isAlreadyStudent = await StudentModel.findOne({ user_id: duplicate._id, is_deleted: false })
                .select('_id')
                .lean()
                .exec();
              if (isAlreadyStudent) {
                results.skipped++;
                continue;
              }
            }

            const genderInput = item.gender?.toString().toLowerCase();
            const gender = genderInput === 'nam' ? 'male' : genderInput === 'nữ' ? 'female' : 'male';

            let targetCourseId = courseId;
            if (importType === 'student_and_course' && item.courseCode) {
              targetCourseId = await this._findOrCreateCourse(item, userId);
              if (!targetCourseId) {
                results.failed++;
                results.errors.push({ name: item.firstName, error: `Không tìm thấy hoặc không thể tạo khóa học: ${item.courseCode}` });
                continue;
              }
            }

            await this.createStudent({
              first_name: item.firstName,
              last_name: item.lastName || '',
              phone: item.phone,
              identity_card: item.identity_card,
              address: item.address,
              license_category_id: item.trainingGrade || item.license_category_id || item.licenseRank,
              existing_license_num: item.existing_license_num || item.licenseNum,
              gender: gender,
              dob: item.dob,
              course_id: targetCourseId,
              amount: item.amount,
              installment: item.installment,
              lead_manager: item.lead_manager || item.leadManager,
              student_code: item.student_code,
              teacher_id: userId,
              contract_date: item.submissionDate,
            });

            results.success++;

            // Progress notification every 5 students
            if (results.success % 5 === 0) {
              await this.notifyService.send({
                userId,
                title: '⏳ Đang nhập dữ liệu...',
                content: `Đã xử lý thành công ${results.success} học viên.`,
                channel: 'in_app',
              });
            }
          } catch (error: any) {
            results.failed++;
            results.errors.push({ name: item.firstName, error: error.message });
            logger.error('Import row failed', { name: item.firstName, courseCode: item.courseCode, error: error.message, stack: error.stack });
          }
        }

        // --- GENERATE SUMMARY REPORT AFTER IMPORT ---
        const stats = await this.getImportManagementStats();

        const summaryContent = [
          `Đã xử lý xong file Excel.`,
          `✅ Thành công: ${results.success}`,
          `⏭️ Bỏ qua (Trùng): ${results.skipped}`,
          `❌ Lỗi: ${results.failed}`,
          results.errors.length > 0
            ? `Chi tiết lỗi: ${results.errors
                .slice(0, 3)
                .map((e) => `${e.name}: ${e.error}`)
                .join('; ')}${results.errors.length > 3 ? '...' : ''}`
            : '',
          `\n📊 BÁO CÁO TỔNG HỢP HỆ THỐNG:`,
          `• Tổng số học viên: ${stats.total}`,
          `• Đã vào khóa: ${stats.enrolled}`,
          `• Chưa vào khóa: ${stats.unassigned}`,
          `• Chờ xếp khóa: ${stats.waiting}`,
          `• Học viên tồn: ${stats.remaining}`,
        ]
          .filter((line) => line !== '')
          .join('\n');

        // Create FINAL notification with the summary report
        await this.notifyService.send({
          userId,
          title: '📑 Hoàn tất nhập dữ liệu học viên',
          content: summaryContent,
          channel: 'in_app',
        });
      } catch (error: any) {
        logger.error('Import process failed', { error: error.message });

        await this.notifyService.send({
          userId,
          title: 'Lỗi nhập dữ liệu học viên',
          content: `Đã xảy ra lỗi nghiêm trọng khi xử lý file: ${error.message}`,
          channel: 'in_app',
        });
      } finally {
        // Cleanup the file
        if (fs.existsSync(filePath)) {
          fs.unlinkSync(filePath);
        }
      }
    };

    // Trigger background execution
    runImport();
    return { message: 'Quá trình nhập dữ liệu đã bắt đầu chạy ngầm' };
  }
}

