import mongoose from 'mongoose';

// Simple in-memory store to simulate MongoDB behavior
class MockStore {
  public data: Map<string, any> = new Map();

  clear() {
    this.data.clear();
  }

  async create(obj: any) {
    const records = Array.isArray(obj) ? obj : [obj];
    const created = records.map(r => {
      const id = r._id || new mongoose.Types.ObjectId().toString();
      const newDoc = { ...r };
      Object.keys(newDoc).forEach(k => {
        if (newDoc[k] && typeof newDoc[k] === 'object' && newDoc[k]._id) {
           newDoc[k] = newDoc[k]._id.toString();
        } else if (newDoc[k] instanceof mongoose.Types.ObjectId) {
           newDoc[k] = newDoc[k].toString();
        }
      });
      newDoc._id = id.toString();
      newDoc.save = jest.fn().mockImplementation(function(this: any) { return Promise.resolve(this); });
      newDoc.toObject = jest.fn().mockImplementation(function(this: any) { return this; });
      this.data.set(newDoc._id, newDoc);
      return newDoc;
    });
    return Array.isArray(obj) ? created : created[0];
  }

  async insertMany(records: any[]) { return this.create(records); }

  find(query: any = {}) {
    let results = Array.from(this.data.values());
    if (query && typeof query === 'object') {
      const keys = Object.keys(query).filter(k => !k.startsWith('$'));
      keys.forEach(key => {
        const val = query[key];
        if (val !== undefined && val !== null) {
          if (typeof val === 'object' && val.$in) {
            const allowed = Array.isArray(val.$in) ? val.$in.map((v: any) => (v?._id || v || '').toString()) : [];
            results = results.filter(r => allowed.includes((r[key]?._id || r[key] || '').toString()));
          } else {
            const searchVal = (val?._id || val || '').toString();
            results = results.filter(r => (r[key]?._id || r[key] || '').toString() === searchVal);
          }
        }
      });
    }
    return results;
  }

  findOne(query: any = {}) { return this.find(query)[0] || null; }
  findById(id: any) { return this.data.get((id?._id || id || '').toString()) || null; }
  findByIdAndUpdate(id: any, update: any) {
    const searchId = (id?._id || id || '').toString();
    const doc = this.data.get(searchId);
    if (!doc) return null;
    const updated = { ...doc, ...(update.$set || update) };
    this.data.set(searchId, updated);
    return updated;
  }
}

const mockStores: Record<string, MockStore> = {
  user: new MockStore(),
  student: new MockStore(),
  course: new MockStore(),
  exam: new MockStore(),
  city: new MockStore(),
  course_student: new MockStore(),
  payment: new MockStore(),
  lesson: new MockStore(),
  datsession: new MockStore(),
  licensecategory: new MockStore(),
  system_log: new MockStore(),
  import_log: new MockStore(),
};

const mockCollectionToStore: Record<string, string> = {
  users: 'user', Users: 'user',
  students: 'student', StudentInfos: 'student', studentinfos: 'student',
  courses: 'course', Courses: 'course',
  exams: 'exam', Exams: 'exam',
  cities: 'city', Cities: 'city',
  coursestudents: 'course_student',
  payments: 'payment',
  lessons: 'lesson',
  datsessions: 'datsession',
  licensecategories: 'licensecategory', LicenseCategories: 'licensecategory',
  system_logs: 'system_log',
  import_logs: 'import_log',
};

const mockEvaluateValue = (r: any, val: any): any => {
  if (typeof val === 'string' && val.startsWith('$')) {
    const field = val.substring(1);
    if (field.includes('.')) {
      const parts = field.split('.');
      let current = r;
      for (const p of parts) current = current?.[p];
      return current;
    }
    return r[field];
  }
  if (typeof val === 'object' && val !== null) {
    if (val.$ifNull) return (mockEvaluateValue(r, val.$ifNull[0]) ?? mockEvaluateValue(r, val.$ifNull[1]));
    if (val.$arrayElemAt) {
      const arr = mockEvaluateValue(r, val.$arrayElemAt[0]);
      if (!Array.isArray(arr)) return null;
      const index = val.$arrayElemAt[1];
      return index === -1 ? arr[arr.length - 1] : arr[index];
    }
    if (val.$toString) return mockEvaluateValue(r, val.$toString)?.toString();
    if (val.$sum) {
       const arr = mockEvaluateValue(r, val.$sum);
       return Array.isArray(arr) ? arr.reduce((acc, curr) => acc + (parseFloat(curr) || 0), 0) : 0;
    }
    if (val.$cond) return mockEvaluateValue(r, val.$cond.if) ? mockEvaluateValue(r, val.$cond.then) : mockEvaluateValue(r, val.$cond.else);
  }
  return val;
};

const mockCreateMockQuery = (result: any) => ({
  exec: jest.fn().mockResolvedValue(result),
  lean: jest.fn().mockReturnThis(),
  select: jest.fn().mockReturnThis(),
  populate: jest.fn().mockReturnThis(),
  sort: jest.fn().mockReturnThis(),
  skip: jest.fn().mockReturnThis(),
  limit: jest.fn().mockReturnThis(),
  then: jest.fn(resolve => resolve(result)),
});

const mockCreateMockModel = (storeName: string) => {
  const store = mockStores[storeName];
  return {
    create: jest.fn().mockImplementation(data => store.create(data)),
    insertMany: jest.fn().mockImplementation(data => store.insertMany(data)),
    find: jest.fn().mockImplementation(q => mockCreateMockQuery(store.find(q))),
    findOne: jest.fn().mockImplementation(q => mockCreateMockQuery(store.findOne(q))),
    findById: jest.fn().mockImplementation(id => mockCreateMockQuery(store.findById(id))),
    findByIdAndUpdate: jest.fn().mockImplementation((id, data) => mockCreateMockQuery(store.findByIdAndUpdate(id, data))),
    findOneAndUpdate: jest.fn().mockImplementation((id, data) => mockCreateMockQuery(store.findByIdAndUpdate(id, data))),
    updateOne: jest.fn().mockImplementation((q, data) => {
        const doc = store.findOne(q);
        if (doc) store.findByIdAndUpdate(doc._id, data);
        return { modifiedCount: doc ? 1 : 0 };
    }),
    deleteOne: jest.fn().mockImplementation(async q => {
       const doc = store.findOne(q);
       if (doc) store.data.delete(doc._id);
       return { deletedCount: doc ? 1 : 0 };
    }),
    deleteMany: jest.fn().mockImplementation(async () => { store.clear(); return { deletedCount: 0 }; }),
    countDocuments: jest.fn().mockImplementation(() => mockCreateMockQuery(store.find().length)),
    aggregate: jest.fn().mockImplementation((pipeline: any[]) => {
      let results = store.find();
      pipeline.forEach(stage => {
        const op = Object.keys(stage)[0];
        if (op === '$match') {
          Object.keys(stage.$match).forEach(key => {
            if (!key.startsWith('$')) {
              const searchVal = (stage.$match[key]?._id || stage.$match[key] || '').toString();
              results = results.filter(r => (r[key]?._id || r[key] || '').toString() === searchVal);
            }
          });
        } else if (op === '$lookup') {
          const { from, localField, foreignField, as } = stage.$lookup;
          const targetStore = mockStores[mockCollectionToStore[from]];
          if (targetStore) {
            results = results.map(r => {
              const localVal = (r[localField]?._id || r[localField] || '').toString();
              const joined = targetStore.find().filter(j => (j[foreignField]?._id || j[foreignField] || '').toString() === localVal);
              return { ...r, [as]: joined };
            });
          }
        } else if (op === '$unwind') {
          const path = typeof stage.$unwind === 'string' ? stage.$unwind : stage.$unwind.path;
          const field = path.startsWith('$') ? path.substring(1) : path;
          results = results.map(r => ({ ...r, [field]: (Array.isArray(r[field]) && r[field].length > 0) ? r[field][0] : null }));
        } else if (op === '$addFields') {
          results = results.map(r => {
            const newR = { ...r };
            Object.keys(stage.$addFields).forEach(k => { newR[k] = mockEvaluateValue(r, stage.$addFields[k]); });
            return newR;
          });
        } else if (op === '$project') {
          results = results.map(r => {
            const newR = { ...r };
            Object.keys(stage.$project).forEach(k => {
              const v = stage.$project[k];
              if (v === 0 || v === false) delete newR[k];
              else if (v !== 1 && v !== true) newR[k] = mockEvaluateValue(r, v);
            });
            return newR;
          });
        }
      });
      const hasFacet = pipeline.some(s => s.$facet);
      const finalResult = hasFacet ? [{ data: results, total: [{ count: results.length }], stats: [] }] : results;
      return { exec: jest.fn().mockResolvedValue(finalResult), then: jest.fn(resolve => resolve(finalResult)) };
    }),
    distinct: jest.fn().mockImplementation(() => mockCreateMockQuery([])),
    init: jest.fn().mockResolvedValue(null),
  };
};

const mockCollectionMock = (name: string) => {
  const storeKey = mockCollectionToStore[name];
  const store = storeKey ? mockStores[storeKey] : new MockStore();
  return {
    insertOne: jest.fn().mockImplementation(doc => store.create(doc)),
    insertMany: jest.fn().mockImplementation(docs => store.insertMany(docs)),
    find: jest.fn().mockImplementation(() => ({ toArray: jest.fn().mockResolvedValue(store.find()) })),
    deleteMany: jest.fn().mockResolvedValue({ deletedCount: 0 })
  };
};

