import { CourseService } from '@/application/services/course.service';
import { CourseModel } from '@/infrastructure/database/models/course.model';
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { AppError } from '@/domain/exceptions/app-error';

describe('CourseService', () => {
  let courseService: CourseService;

  beforeEach(() => {
    courseService = new CourseService();
  });

  it('should list all courses', async () => {
    await CourseModel.create([
      { code: 'A1', name: 'Khóa A1', start_date: new Date(), status: 'ongoing' as any },
      { code: 'B1', name: 'Khóa B1', start_date: new Date(), status: 'ongoing' as any }
    ]);

    const result = await courseService.getAllCourses();

    expect(result.data).toHaveLength(2);
    // Note: CourseRepository sorts by start_date: -1, so the last created course comes first if dates are same/close
    expect(result.data.map(c => c.code)).toContain('A1');
    expect(result.data.map(c => c.code)).toContain('B1');
  });

  it('should get course by id', async () => {
    const course = await CourseModel.create({
      code: 'C1',
      name: 'Khóa C1',
      start_date: new Date(),
      status: 'ongoing' as any
    });

    const found = await courseService.getCourseById(course._id.toString());

    expect(found).toBeDefined();
    expect(found?.code).toBe('C1');
  });

  it('should create course via service', async () => {
    const courseData = {
      code: 'SC-1',
      name: 'Service Course 1',
      start_date: new Date(),
      status: 'ongoing' as any
    };

    const created = await courseService.createCourse(courseData as any);

    expect(created.code).toBe('SC-1');
  });

  // ─── Validation tests ──────────────────────────────────────────────────────

  describe('createCourse validation', () => {
    it('should create course when end_date >= start_date (future end_date)', async () => {
      const created = await courseService.createCourse({
        code: 'VALID-DATE-1',
        name: 'Course with valid dates',
        start_date: new Date('2026-05-01'),
        end_date: new Date('2026-06-01'),
        status: 'draft',
      } as any);

      expect(created.code).toBe('VALID-DATE-1');
    });

    it('should create course when start_date equals end_date', async () => {
      const sameDate = new Date('2026-05-01');
      const created = await courseService.createCourse({
        code: 'SAME-DATE-1',
        name: 'One-day course',
        start_date: sameDate,
        end_date: sameDate,
        status: 'draft',
      } as any);

      expect(created.code).toBe('SAME-DATE-1');
    });

    it('should reject course when end_date is before start_date', async () => {
      await expect(
        courseService.createCourse({
          name: 'Invalid dates course',
          start_date: new Date('2026-06-01'),
          end_date: new Date('2026-05-01'),
          status: 'draft',
        } as any)
      ).rejects.toThrow();
    });
  });

  describe('assignStudentsToCourse validation', () => {
    it('should throw when student list is empty', async () => {
      await expect(courseService.assignStudentsToCourse('some-course-id', [])).rejects.toThrow(
        /chọn học viên/i
      );
    });

    it('should throw when student list is null/undefined', async () => {
      await expect(
        courseService.assignStudentsToCourse('some-course-id', null as any)
      ).rejects.toThrow(/chọn học viên/i);
    });

    it('should assign students when course has capacity', async () => {
      const course = await CourseModel.create({
        code: 'ASSIGN-OK',
        name: 'Course with capacity',
        max_students: 5,
        start_date: new Date(),
        status: 'ongoing',
      } as any);

      // Pre-enroll 3 students
      const enrolled = await CourseStudentModel.create([
        { course_id: course._id, student_id: 'sid1', status: 'unfinished' },
        { course_id: course._id, student_id: 'sid2', status: 'unfinished' },
        { course_id: course._id, student_id: 'sid3', status: 'unfinished' },
      ]);

      const result = await courseService.assignStudentsToCourse(course._id.toString(), ['nsid1', 'nsid2']);

      expect(result).toBeDefined();
    });
  });

  describe('bulkUpdateCourseStatus validation', () => {
    it('should throw AppError for invalid status', async () => {
      await expect(
        courseService.bulkUpdateCourseStatus(['course1', 'course2'], 'invalid_status', 'teacher1')
      ).rejects.toThrow(AppError);
    });
  });
});

