import { CourseService } from '@/application/services/course.service';
import { CourseModel } from '@/infrastructure/database/models/course.model';
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { AppError } from '@/domain/exceptions/app-error';

describe('CourseService', () => {
  let courseService: CourseService;

  beforeEach(() => {
    courseService = new CourseService();
  });

  it('should list all courses', async () => {
    await CourseModel.create([
      { code: 'A1', name: 'Khóa A1', start_date: new Date(), status: 'ongoing' as any },
      { code: 'B1', name: 'Khóa B1', start_date: new Date(), status: 'ongoing' as any }
    ]);

    const result = await courseService.getAllCourses();

    expect(result.data).toHaveLength(2);
    // Note: CourseRepository sorts by start_date: -1, so the last created course comes first if dates are same/close
    expect(result.data.map(c => c.code)).toContain('A1');
    expect(result.data.map(c => c.code)).toContain('B1');
  });

  it('should get course by id', async () => {
    const course = await CourseModel.create({
      code: 'C1',
      name: 'Khóa C1',
      start_date: new Date(),
      status: 'ongoing' as any
    });

    const found = await courseService.getCourseById(course._id.toString());

    expect(found).toBeDefined();
    expect(found?.code).toBe('C1');
  });

  it('should create course via service', async () => {
    const courseData = {
      code: 'SC-1',
      name: 'Service Course 1',
      start_date: new Date(),
      status: 'ongoing' as any
    };

    const created = await courseService.createCourse(courseData as any);

    expect(created.code).toBe('SC-1');
  });

  // ─── Validation tests ──────────────────────────────────────────────────────

  describe('createCourse validation', () => {
    it('should create course when end_date >= start_date (future end_date)', async () => {
      const created = await courseService.createCourse({
        code: 'VALID-DATE-1',
        name: 'Course with valid dates',
        start_date: new Date('2026-05-01'),
        end_date: new Date('2026-06-01'),
        status: 'draft',
      } as any);

      expect(created.code).toBe('VALID-DATE-1');
    });

    it('should create course when start_date equals end_date', async () => {
      const sameDate = new Date('2026-05-01');
      const created = await courseService.createCourse({
        code: 'SAME-DATE-1',
        name: 'One-day course',
        start_date: sameDate,
        end_date: sameDate,
        status: 'draft',
      } as any);

      expect(created.code).toBe('SAME-DATE-1');
    });

    it('should reject course when end_date is before start_date', async () => {
      await expect(
        courseService.createCourse({
          name: 'Invalid dates course',
          start_date: new Date('2026-06-01'),
          end_date: new Date('2026-05-01'),
          status: 'draft',
        } as any)
      ).rejects.toThrow();
    });
  });

  describe('assignStudentsToCourse validation', () => {
    it('should throw when student list is empty', async () => {
      await expect(courseService.assignStudentsToCourse('some-course-id', [])).rejects.toThrow(
        /chọn học viên/i
      );
    });

    it('should throw when student list is null/undefined', async () => {
      await expect(
        courseService.assignStudentsToCourse('some-course-id', null as any)
      ).rejects.toThrow(/chọn học viên/i);
    });

    it('should assign students when course has capacity', async () => {
      const course = await CourseModel.create({
        code: 'ASSIGN-OK',
        name: 'Course with capacity',
        max_students: 5,
        start_date: new Date(),
        status: 'ongoing',
      } as any);

      // Pre-enroll 3 students
      const enrolled = await CourseStudentModel.create([
        { course_id: course._id, student_id: 'sid1', status: 'unfinished' },
        { course_id: course._id, student_id: 'sid2', status: 'unfinished' },
        { course_id: course._id, student_id: 'sid3', status: 'unfinished' },
      ]);

      const result = await courseService.assignStudentsToCourse(course._id.toString(), ['nsid1', 'nsid2']);

      expect(result).toBeDefined();
    });
  });

  describe('bulkUpdateCourseStatus validation', () => {
    // Use valid ObjectId format so the service reaches status validation,
    // not the ObjectId constructor which throws BSONError first.
    const VALID_TEACHER_ID = '507f1f77bcf86cd799439011';

    it('should throw AppError for invalid status', async () => {
      await expect(
        courseService.bulkUpdateCourseStatus(
          ['507f1f77bcf86cd799439012', '507f1f77bcf86cd799439013'],
          'invalid_status',
          VALID_TEACHER_ID
        )
      ).rejects.toThrow(AppError);
    });
  });
});

import { StudentService } from '@/application/services/student.service';
import { StudentModel } from '@/infrastructure/database/models/student.model';
import { UserModel, IUser } from '@/infrastructure/database/models/user.model';
import { CourseModel } from '@/infrastructure/database/models/course.model';
import { AppError } from '@/domain/exceptions/app-error';

describe('StudentService', () => {
  let studentService: StudentService;
  let testUser: any;

  beforeEach(async () => {
    studentService = new StudentService();

    testUser = await UserModel.create({
      username: 'test_student_svc',
      first_name: 'Service',
      last_name: 'Test',
      email: 'svc@example.com',
      phone: '000001',
      address: 'Service Address',
      identity_card: '111112',
      password: 'testPassword123'
    });
  });

  it('should get all students', async () => {
    await StudentModel.create([
      { user_id: testUser._id, status_detail: 'Học lý thuyết' }
    ]);

    const students = await studentService.getAllStudents();

    expect(students.data).toHaveLength(1);
    expect(students.data[0].status_detail).toBe('Học lý thuyết');

    // Ensure user_id is present (either as ID or object)
    expect(students.data[0].user_id).toBeDefined();
  });

  it('should create a student via service', async () => {
    const studentData = {
      user_id: testUser._id,
      status_detail: 'Chờ KSK'
    };

    const student = await studentService.createStudent(studentData as any);

    expect(student.status_detail).toBe('Chờ KSK');
    const studentUserId = (student.user_id as any)?._id || student.user_id;
    expect(studentUserId.toString()).toBe(testUser._id.toString());
  });

  // ─── Pagination & filtering ───────────────────────────────────────────────

  describe('getAllStudents pagination', () => {
    it('should return paginated results with default page and limit', async () => {
      const result = await studentService.getAllStudents();

      expect(result.meta).toBeDefined();
      expect(result.meta.page).toBe(1);
      expect(result.meta.limit).toBe(10);
    });

    it('should accept custom pagination options', async () => {
      const result = await studentService.getAllStudents({}, { page: 2, limit: 5 });

      expect(result.meta.page).toBe(2);
      expect(result.meta.limit).toBe(5);
    });
  });

  // ─── createStudent validation ───────────────────────────────────────────────

  describe('createStudent validation', () => {
    it('should auto-assign status_detail when course_id is provided', async () => {
      const studentData = {
        user_id: testUser._id,
        course_id: null,
        status_detail: undefined,
      };

      const student = await studentService.createStudent(studentData as any);

      // Without course_id, default status should be 'Chờ KSK'
      expect(student.status_detail).toBe('Chờ KSK');
    });

    it('should throw when duplicate user is already a student', async () => {
      // First creation succeeds
      const existingStudent = await studentService.createStudent({
        user_id: testUser._id,
        status_detail: 'Chờ KSK',
      } as any);

      // Second creation with same user_id should throw
      await expect(
        studentService.createStudent({
          user_id: testUser._id,
          status_detail: 'Chờ KSK',
        } as any)
      ).rejects.toThrow(AppError);
    });
  });

  // ─── bulkDeleteStudents validation ─────────────────────────────────────────

  describe('bulkDeleteStudents validation', () => {
    it('should throw when ids list is empty', async () => {
      await expect(studentService.bulkDeleteStudents([])).rejects.toThrow(
        /Danh sách ID không được để trống/i
      );
    });
  });

  // ─── getStudentById ─────────────────────────────────────────────────────────

  describe('getStudentById', () => {
    it('should return student when found', async () => {
      const created = await StudentModel.create({
        user_id: testUser._id,
        status_detail: 'Đang học',
      });

      const found = await studentService.getStudentById((created as any)._id.toString());

      expect(found).toBeDefined();
      expect((found as any).status_detail).toBe('Đang học');
    });

    it('should throw AppError when student not found', async () => {
      await expect(
        studentService.getStudentById('000000000000000000000000')
      ).rejects.toThrow(AppError);
    });
  });

  // ─── isStudentAssignedToTeacher ──────────────────────────────────────────────

  describe('isStudentAssignedToTeacher', () => {
    it('should return false when student is not assigned to teacher', async () => {
      const result = await studentService.isStudentAssignedToTeacher(
        'nonexistent-student-id',
        'nonexistent-teacher-id'
      );

      expect(result).toBe(false);
    });
  });
});
